def _rotate_file(path: str, backup_count: int) -> None:
    # rotate path -> path.1, path.1 -> path.2, ... keep up to backup_count
    if backup_count <= 0:
        return
    for i in range(backup_count - 1, 0, -1):
        s = f"{path}.{i}"
        d = f"{path}.{i+1}"
        if os.path.exists(s):
