def _read_full_or_snippet(root: str, meta: Dict, max_chars: int = 4000) -> str:
    path = os.path.join(root, meta["path"])
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            text = f.read()
            return text[:max_chars]
    except Exception:
